QUEUE_FIELDNAMES = [
    "priority",
    "track",
    "surface",
    "rows",
    "bytes",
    "promotion_ready_bytes",
    "signal_score",
    "status",
    "next_action",
    "positive_evidence",
    "blocking_evidence",
]

SUMMARY_FIELDNAMES = [
    "scope",
    "decision_rows",
    "total_bytes",
    "promotion_ready_bytes",
    "blocked_rows",
    "blocked_bytes",
    "tracks",
    "top_track",
    "top_surface",
    "top_action",
    "issue_rows",
]


TRACK_RULES = [
    ("gradient", ("gradient", "seed", "delta")),
    ("flat_walk", ("flat", "plateau", "palette")),
    ("jump", ("jump", "nibble", "dense", "residual")),
    ("mixed_token", ("mixed_token", "mixed-token", "band")),
    ("control", ("control", "signal", "phase", "payload")),
    ("direction_value", ("direction_value", "direction-value", "value")),
]


def read_rows(path: Path) -> list[dict[str, str]]:
    with path.open(newline="") as handle:
        return list(csv.DictReader(handle))


def read_optional_summary(path: Path) -> dict[str, str] | None:
    if not path.exists():
        return None
    rows = read_rows(path)
    return rows[0] if rows else None


def write_csv(path: Path, fieldnames: list[str], rows: list[dict[str, object]]) -> None:
    with path.open("w", newline="") as handle:
        writer = csv.DictWriter(handle, fieldnames=fieldnames)
        writer.writeheader()
        writer.writerows(rows)


def int_value(row: dict[str, str], field: str) -> int:
    raw = row.get(field, "")
    try:
        return int(raw) if raw else 0
    except ValueError:
        return 0


def classify_track(row: dict[str, str]) -> str:
    surface = row.get("surface", "").lower()
    if surface.startswith("mixed_token"):
        return "mixed_token"
    if surface.startswith("jump") or surface.startswith("dense") or surface.startswith("residual"):
        return "jump"
    if surface.startswith("direction_value"):
        return "direction_value"
    if surface.startswith("flat_walk"):
        return "flat_walk"
    if surface.startswith("gradient"):
        return "gradient"
    if "control" in surface or "signal" in surface:
        return "control"

    text = " ".join(
        [
            surface,
            row.get("next_action", ""),
            row.get("positive_evidence", ""),
            row.get("blocking_evidence", ""),
        ]
    ).lower()
    for track, needles in TRACK_RULES:
        if any(needle in text for needle in needles):
            return track
    return "general"


def signal_score(row: dict[str, str]) -> int:
    positive = row.get("positive_evidence", "").lower()
    blocking = row.get("blocking_evidence", "").lower()
    score = 0
    for word, weight in [
        ("repeated", 8),
        ("copy_unlock", 7),
        ("copy_distance", 6),
        ("candidate", 5),
        ("exact", 4),
        ("ge75", 3),
        ("dominant", 2),
    ]:
        score += positive.count(word) * weight
    for word, weight in [
        ("promotion_ready=0", 8),
        ("conflicted", 5),
        ("false", 5),
        ("singleton", 3),
        ("reject", 3),
    ]:
        score -= blocking.count(word) * weight
    return score


def append_evidence(existing: str, extra: list[str]) -> str:
    values = [existing] if existing else []
    values.extend(value for value in extra if value)
    return "; ".join(values)


def apply_terminal_root_source_byte_cascade(
    queue: list[dict[str, str]],
    *,
    first_promoted: dict[str, str] | None,
    second_review: dict[str, str] | None,
    second_promoted: dict[str, str] | None,
    third_review: dict[str, str] | None,
    third_promoted: dict[str, str] | None,
    third_dependency: dict[str, str] | None,
    third_residual: dict[str, str] | None,
    fourth_review: dict[str, str] | None,
    terminal_root_review: dict[str, str] | None,
) -> list[dict[str, str]]:
    if not any(
        (
            first_promoted,
            second_review,
            second_promoted,
            third_review,
            third_promoted,
            third_dependency,
            third_residual,
            fourth_review,
            terminal_root_review,
        )
    ):
        return queue

    updated: list[dict[str, str]] = []
    for row in queue:
        if row.get("surface", "") != "gradient_like":
            updated.append(row)
            continue
        positive_evidence = row.get("positive_evidence", "")
        blocking_evidence = row.get("blocking_evidence", "")
        for label, summary in (
            ("first", first_promoted),
            ("second", second_promoted),
            ("third", third_promoted),
        ):
            if not summary:
                continue
            positive_evidence = append_evidence(
                positive_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_root_source_byte_{label}_added="
                    f"{summary.get('source_added_bytes', '0')}/{summary.get('target_rows', '0')}",
                    f"gradient_sequence_low_exception_terminal_root_source_byte_{label}_total_clean="
                    f"{summary.get('total_clean_bytes', '0')}",
                ],
            )
            blocking_evidence = append_evidence(
                blocking_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_root_source_byte_{label}_false="
                    f"{summary.get('source_false_bytes', '0')}",
                    f"gradient_sequence_low_exception_terminal_root_source_byte_{label}_issues="
                    f"{summary.get('issue_rows', '0')}",
                ],
            )
        for label, summary in (("second", second_review), ("third", third_review)):
            if not summary:
                continue
            positive_evidence = append_evidence(
                positive_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_root_source_byte_{label}_guard="
                    f"{summary.get('best_formula', '')}/{summary.get('best_guard_key', '')}",
                    f"gradient_sequence_low_exception_terminal_root_source_byte_{label}_ready="
                    f"{summary.get('promotion_ready_bytes', '0')}",
                ],
            )
        if third_dependency:
            positive_evidence = append_evidence(
                positive_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_root_source_byte_dependency_available="
                    f"{third_dependency.get('source_available_slots', '0')}/{third_dependency.get('slots', '0')}",
                    f"gradient_sequence_low_exception_terminal_root_source_byte_highsafe_unknown="
                    f"{third_dependency.get('source_unknown_in_highsafe_slots', '0')}",
                ],
            )
            blocking_evidence = append_evidence(
                blocking_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_root_source_byte_outside_unknown="
                    f"{third_dependency.get('source_unknown_outside_highsafe_slots', '0')}",
                    f"gradient_sequence_low_exception_terminal_root_source_byte_top_unknown="
                    f"{third_dependency.get('top_unknown_dependency_edge', '')}:"
                    f"{third_dependency.get('top_unknown_dependency_edge_slots', '0')}",
                    f"gradient_sequence_low_exception_terminal_root_source_byte_dependency_issues="
                    f"{third_dependency.get('issue_rows', '0')}",
                ],
            )
        if third_residual:
            positive_evidence = append_evidence(
                positive_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_root_source_byte_residual_known_chains="
                    f"{third_residual.get('terminal_known_chains', '0')}",
                    f"gradient_sequence_low_exception_terminal_root_source_byte_residual_external_chains="
                    f"{third_residual.get('terminal_unknown_outside_chains', '0')}",
                ],
            )
            blocking_evidence = append_evidence(
                blocking_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_root_source_byte_residual_top_unknown="
                    f"{third_residual.get('top_unknown_edge', '')}:"
                    f"{third_residual.get('top_unknown_edge_unknown_slots', '0')}",
                    f"gradient_sequence_low_exception_terminal_root_source_byte_residual_blocker="
                    f"{third_residual.get('dominant_blocker', '')}",
                    f"gradient_sequence_low_exception_terminal_root_source_byte_residual_issues="
                    f"{third_residual.get('issue_rows', '0')}",
                ],
            )
        if fourth_review:
            blocking_evidence = append_evidence(
                blocking_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_root_source_byte_fourth_verdict="
                    f"{fourth_review.get('review_verdict', '')}",
                    f"gradient_sequence_low_exception_terminal_root_source_byte_fourth_ready="
                    f"{fourth_review.get('promotion_ready_bytes', '0')}",
                    f"gradient_sequence_low_exception_terminal_root_source_byte_fourth_issues="
                    f"{fourth_review.get('issue_rows', '0')}",
                ],
            )
        if terminal_root_review:
            blocking_evidence = append_evidence(
                blocking_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_root_after_source_byte_candidate="
                    f"{terminal_root_review.get('promotion_candidate_bytes', '0')}",
                    f"gradient_sequence_low_exception_terminal_root_after_source_byte_unknown_roots="
                    f"{terminal_root_review.get('unknown_root_rows', '0')}",
                    f"gradient_sequence_low_exception_terminal_root_after_source_byte_issues="
                    f"{terminal_root_review.get('issue_rows', '0')}",
                ],
            )

        next_action = "derive stronger terminal transform after terminal/root source-byte cascade"
        if fourth_review and int_value(fourth_review, "promotion_ready_bytes") > 0:
            next_action = "promote fourth terminal/root source-byte guard"
        elif terminal_root_review and int_value(terminal_root_review, "promotion_candidate_bytes") > 0:
            next_action = "promote terminal/root transform after source-byte cascade"

        updated.append(
            {
                **row,
                "promotion_ready_bytes": fourth_review.get("promotion_ready_bytes", "0") if fourth_review else "0",
                "next_action": next_action,
                "positive_evidence": positive_evidence,
                "blocking_evidence": blocking_evidence,
            }
        )
    return updated


def apply_terminal_source_byte_cascade(
    queue: list[dict[str, str]],
    *,
    base_promoted: dict[str, str] | None,
    final_promoted: dict[str, str] | None,
    final_dependency: dict[str, str] | None,
    final_residual: dict[str, str] | None,
    stop_review: dict[str, str] | None,
) -> list[dict[str, str]]:
    if not any((base_promoted, final_promoted, final_dependency, final_residual, stop_review)):
        return queue

    updated: list[dict[str, str]] = []
    for row in queue:
        if row.get("surface", "") != "gradient_like":
            updated.append(row)
            continue
        positive_evidence = row.get("positive_evidence", "")
        blocking_evidence = row.get("blocking_evidence", "")
        if final_promoted:
            added_total = ""
            if base_promoted:
                added_total = str(
                    max(
                        0,
                        int_value(final_promoted, "total_clean_bytes")
                        - int_value(base_promoted, "total_clean_bytes"),
                    )
                )
            positive_evidence = append_evidence(
                positive_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_source_byte_cascade_added={added_total}",
                    f"gradient_sequence_low_exception_terminal_source_byte_cascade_total_clean="
                    f"{final_promoted.get('total_clean_bytes', '0')}",
                    f"gradient_sequence_low_exception_terminal_source_byte_cascade_remaining="
                    f"{final_promoted.get('remaining_unresolved_bytes', '0')}",
                ],
            )
            blocking_evidence = append_evidence(
                blocking_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_source_byte_cascade_false="
                    f"{final_promoted.get('source_false_bytes', '0')}",
                    f"gradient_sequence_low_exception_terminal_source_byte_cascade_issues="
                    f"{final_promoted.get('issue_rows', '0')}",
                ],
            )
        if final_dependency:
            positive_evidence = append_evidence(
                positive_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_source_byte_dependency_available="
                    f"{final_dependency.get('source_available_slots', '0')}/{final_dependency.get('slots', '0')}",
                    f"gradient_sequence_low_exception_terminal_source_byte_highsafe_unknown="
                    f"{final_dependency.get('source_unknown_in_highsafe_slots', '0')}",
                ],
            )
            blocking_evidence = append_evidence(
                blocking_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_source_byte_outside_unknown="
                    f"{final_dependency.get('source_unknown_outside_highsafe_slots', '0')}",
                    f"gradient_sequence_low_exception_terminal_source_byte_top_unknown="
                    f"{final_dependency.get('top_unknown_dependency_edge', '')}:"
                    f"{final_dependency.get('top_unknown_dependency_edge_slots', '0')}",
                    f"gradient_sequence_low_exception_terminal_source_byte_dependency_issues="
                    f"{final_dependency.get('issue_rows', '0')}",
                ],
            )
        if final_residual:
            positive_evidence = append_evidence(
                positive_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_source_byte_residual_known_chains="
                    f"{final_residual.get('terminal_known_chains', '0')}",
                    f"gradient_sequence_low_exception_terminal_source_byte_residual_external_chains="
                    f"{final_residual.get('terminal_unknown_outside_chains', '0')}",
                ],
            )
            blocking_evidence = append_evidence(
                blocking_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_source_byte_residual_top_unknown="
                    f"{final_residual.get('top_unknown_edge', '')}:"
                    f"{final_residual.get('top_unknown_edge_unknown_slots', '0')}",
                    f"gradient_sequence_low_exception_terminal_source_byte_residual_blocker="
                    f"{final_residual.get('dominant_blocker', '')}",
                    f"gradient_sequence_low_exception_terminal_source_byte_residual_issues="
                    f"{final_residual.get('issue_rows', '0')}",
                ],
            )
        if stop_review:
            blocking_evidence = append_evidence(
                blocking_evidence,
                [
                    f"gradient_sequence_low_exception_terminal_source_byte_stop_verdict="
                    f"{stop_review.get('review_verdict', '')}",
                    f"gradient_sequence_low_exception_terminal_source_byte_stop_ready="
                    f"{stop_review.get('promotion_ready_bytes', '0')}",
                    f"gradient_sequence_low_exception_terminal_source_byte_stop_issues="
                    f"{stop_review.get('issue_rows', '0')}",
                ],
            )

        ready_bytes = stop_review.get("promotion_ready_bytes", "0") if stop_review else "0"
        highsafe_unknown = final_dependency.get("source_unknown_in_highsafe_slots", "0") if final_dependency else "0"
        next_action = "derive broader terminal-source byte transform for known-terminal chains"
        if int_value({"ready": ready_bytes}, "ready") > 0:
            next_action = "promote next terminal-source byte guard"
        elif highsafe_unknown:
            next_action = f"derive broader terminal-source byte transform for {highsafe_unknown} known-terminal chains"

        updated.append(
            {
                **row,
                "promotion_ready_bytes": ready_bytes,
                "next_action": next_action,
                "positive_evidence": positive_evidence,
                "blocking_evidence": blocking_evidence,
            }
        )
    return updated


